blocks.body:
{
    "level": "A1",
    "intro": "Konstrukcje <strong>have got / has got</strong> pomagają powiedzieć, <strong>co ktoś ma</strong>: rzecz, zwierzę, członka rodziny albo inną prostą własność.",
    "rules": [
        {
            "label": "I / you / we / they",
            "color": "emerald",
            "text": "Z tymi podmiotami używaj <strong>have got</strong>.",
            "example": "I have got a book. / They have got a car."
        },
        {
            "label": "He / she / it",
            "color": "blue",
            "text": "Z <strong>he / she / it</strong> używaj <strong>has got</strong>.",
            "example": "He has got a dog. / She has got a cat."
        },
        {
            "label": "Pełne formy",
            "color": "amber",
            "text": "Na poziomie A1 najłatwiej trzymać się pełnych form w przeczeniach i pytaniach: <strong>have not got / has not got</strong>, <strong>Have ... got?</strong>, <strong>Has ... got?</strong>.",
            "example": "We have not got a house. / Has she got a cat?"
        }
    ]
}

{
    "title": "1. Podstawowe formy",
    "intro": "Zapamiętaj, która forma pasuje do którego podmiotu.",
    "items": [
        {
            "label": "I / You / We / They",
            "title": "have got",
            "subtitle": "I have got a book. / They have got a car."
        },
        {
            "label": "He / She / It",
            "title": "has got",
            "subtitle": "He has got a dog. / She has got two books."
        },
        {
            "label": "Negative",
            "title": "have not got / has not got",
            "subtitle": "You have not got a cat. / He has not got a brother."
        },
        {
            "label": "Questions",
            "title": "Have / Has + subject + got",
            "subtitle": "Have you got a book? / Has she got a cat?"
        }
    ]
}

{
    "title": "2. Kiedy używamy have got / has got",
    "sections": [
        {
            "label": "Przedmioty i rzeczy",
            "color": "emerald",
            "description": "Używaj <strong>have got / has got</strong>, gdy mówisz o rzeczach, które ktoś ma.",
            "examples": [
                {
                    "en": "I have got a book.",
                    "ua": "Mam książkę."
                },
                {
                    "en": "They have got a car.",
                    "ua": "Mają samochód."
                }
            ]
        },
        {
            "label": "Rodzina i zwierzęta",
            "color": "blue",
            "description": "Ta konstrukcja często opisuje krewnych, zwierzęta domowe albo bliskie osoby.",
            "examples": [
                {
                    "en": "I have got a sister.",
                    "ua": "Mam siostrę."
                },
                {
                    "en": "She has got a cat.",
                    "ua": "Ona ma kota."
                }
            ]
        },
        {
            "label": "Przeczenia i pytania",
            "color": "amber",
            "description": "Na A1 najczytelniejsze są pełne formy: <strong>have not got / has not got</strong> oraz pytania z <strong>Have / Has</strong> na początku.",
            "examples": [
                {
                    "en": "He has not got a brother.",
                    "ua": "On nie ma brata."
                },
                {
                    "en": "What have you got?",
                    "ua": "Co masz?"
                }
            ],
            "note": "📌 Po <strong>have / has</strong> w tej konstrukcji stoi <strong>got</strong>."
        }
    ]
}

{
    "title": "3. Szybka tabela",
    "intro": "Jeden prosty model dla każdego typu zdania.",
    "rows": [
        {
            "en": "I / You / We / They",
            "ua": "have got",
            "note": "We have got a house."
        },
        {
            "en": "He / She / It",
            "ua": "has got",
            "note": "She has got two books."
        },
        {
            "en": "Negative",
            "ua": "have not got / has not got",
            "note": "I have not got a car. / He has not got a brother."
        },
        {
            "en": "Question",
            "ua": "Have / Has + subject + got?",
            "note": "Have they got a car? / Has he got a dog?"
        }
    ],
    "warning": "📌 Na tym poziomie trzymaj się pełnych form: <strong>have got, has got, have not got, has not got</strong>."
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "Używaj <strong>have got</strong> z <strong>I / you / we / they</strong>.",
        "Używaj <strong>has got</strong> z <strong>he / she / it</strong>.",
        "Przeczenie: <strong>have not got / has not got</strong>.",
        "Pytanie: <strong>Have / Has + subject + got?</strong>",
        "Pytania wh też zachowują układ <strong>have / has + subject + got</strong>: <strong>What have you got?</strong>, <strong>What has he got?</strong>"
    ]
}
